arguments.command:
cat <<'EOF' > /tmp/stackalloc_test/Program.cs
Span<nint> signed = stackalloc nint[4];
Span<nuint> unsigned = stackalloc nuint[4];

for (int i = 0; i < 4; i++)
{
    signed[i] = i * 10;
    unsigned[i] = (nuint)(i * 20);
}

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"signed:   [{string.Join(", ", signed.ToArray())}]");
Console.WriteLine($"unsigned: [{string.Join(", ", unsigned.ToArray())}]");
EOF
